'use client'

import { useState, useEffect } from 'react'
import Link from 'next/link'
import { useRouter } from 'next/navigation'
import type { Order } from '@food-app/shared'
import { useAuth } from '@/context/AuthContext'
import { Navbar } from '@/components/layout/Navbar'
import { Badge } from '@/components/ui/Badge'
import { Button } from '@/components/ui/Button'
import { Spinner } from '@/components/ui/Spinner'
import { formatPrice, formatDate } from '@/lib/utils'

const STATUS_LABELS: Record<string, string> = {
  placed: 'Order Placed',
  preparing: 'Preparing',
  out_for_delivery: 'Out for Delivery',
  delivered: 'Delivered',
  cancelled: 'Cancelled',
}

const STATUS_VARIANTS: Record<string, 'default' | 'success' | 'warning' | 'error' | 'info'> = {
  placed: 'info',
  preparing: 'warning',
  out_for_delivery: 'info',
  delivered: 'success',
  cancelled: 'error',
}

export default function OrdersPage() {
  const { isAuthenticated, isLoading, token } = useAuth()
  const router = useRouter()
  const [orders, setOrders] = useState<Order[]>([])
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    if (isLoading) return
    if (!isAuthenticated) { router.replace('/login'); return }
    fetch('/api/orders', { headers: { Authorization: `Bearer ${token}` } })
      .then((r) => r.json())
      .then((data) => setOrders(data.orders ?? []))
      .finally(() => setLoading(false))
  }, [isAuthenticated, isLoading, token, router])

  if (isLoading || loading) {
    return (
      <>
        <Navbar />
        <div className="flex justify-center py-20">
          <Spinner className="h-8 w-8 text-orange-500" />
        </div>
      </>
    )
  }

  return (
    <>
      <Navbar />
      <main className="mx-auto max-w-2xl px-4 py-8">
        <h1 className="mb-6 text-2xl font-bold text-gray-900">My Orders</h1>

        {orders.length === 0 ? (
          <div className="py-20 text-center text-gray-500">
            <p className="text-4xl mb-3">📦</p>
            <p className="font-medium">No orders yet</p>
            <p className="text-sm mt-1">Place your first order to see it here</p>
            <Button className="mt-6" onClick={() => router.push('/restaurants')}>
              Order Now
            </Button>
          </div>
        ) : (
          <div className="flex flex-col gap-4">
            {orders.map((order) => (
              <Link key={order.id} href={`/orders/${order.id}`}>
                <div className="rounded-xl border border-gray-200 bg-white p-5 hover:shadow-md transition">
                  <div className="flex items-start justify-between gap-4">
                    <div>
                      <h3 className="font-semibold text-gray-900">{order.restaurantName}</h3>
                      <p className="mt-1 text-sm text-gray-500">
                        {order.items.map((i) => `${i.name} ×${i.quantity}`).join(', ')}
                      </p>
                      <p className="mt-1 text-xs text-gray-400">{formatDate(order.placedAt)}</p>
                    </div>
                    <div className="flex flex-col items-end gap-2 shrink-0">
                      <Badge variant={STATUS_VARIANTS[order.status]}>
                        {STATUS_LABELS[order.status]}
                      </Badge>
                      <span className="text-sm font-semibold text-gray-900">
                        {formatPrice(order.total)}
                      </span>
                    </div>
                  </div>
                </div>
              </Link>
            ))}
          </div>
        )}
      </main>
    </>
  )
}
